    input  wire       clk,
    input  wire       pass_request,
    output wire [7:0] clock,
    output reg        red,
    output reg        yellow,
    output reg        green
);

parameter idle      = 2'd0;
parameter s1_red    = 2'd1;
parameter s2_yellow = 2'd2;
parameter s3_green  = 2'd3;

reg [7:0] cnt;
reg [1:0] state;
reg       p_red, p_yellow, p_green;

assign clock = cnt;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        state <= s1_red;
        cnt   <= 8'd10;
    end else begin
        case (state)
            idle: begin
                state <= s1_red;
                cnt   <= 8'd10;
            end

            s1_red: begin
                if (cnt > 8'd1) begin
                    cnt <= cnt - 8'd1;
                end else begin
                    state <= s3_green;
                    cnt   <= 8'd60;
                end
            end

